"use client";

import { useEffect, useState } from "react";
import { MotionReveal } from "./motion-reveal";

const ROLES = [
  "Médico de Familia",
  "Médico General",
  "Urgenciólogo",
  "Residente"
];

export function SpecialtiesVisual() {
  const [activeRole, setActiveRole] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setActiveRole((prev) => (prev + 1) % ROLES.length);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <section className="relative z-10 min-h-[100svh] bg-black py-24 md:py-32 overflow-hidden flex items-center">
      {/* Background - minimal/clean black style */}
      <div className="pointer-events-none absolute inset-0 bg-black" />

      <div className="mx-auto max-w-7xl px-6 lg:px-8 relative w-full">
        <div className="grid lg:grid-cols-2 gap-16 items-center">

          {/* Left Column: Orbit Visual */}
          <MotionReveal durationMs={800} className="relative h-[500px] flex items-center justify-center">
            <div className="relative w-[500px] h-[500px] scale-[0.55] sm:scale-[0.75] lg:scale-100 transition-transform duration-500">

              {/* Outer Ring (Faint) */}
              <div className="absolute inset-0 rounded-full border border-white/10 opacity-50" />

              {/* Inner Ring (Faint) */}
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[340px] h-[340px] rounded-full border border-white/10 opacity-50" />

              {/* Central Pill */}
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20">
                <div className="flex items-center rounded-[32px] bg-white p-1.5 pr-1.5 shadow-[0_0_40px_rgba(255,255,255,0.1)]">
                  <div className="pl-6 pr-4 text-xl font-medium text-black">
                    Soy
                  </div>
                  <div className="flex h-12 items-center justify-center rounded-full bg-[#b7f453] px-6 text-xl font-bold text-black min-w-[220px] whitespace-nowrap">
                    {ROLES[activeRole]}
                  </div>
                </div>
              </div>

              {/* Orbiting Badges */}
              {/* Note: animation-duration must match for container and item reverse-spin to keep text upright */}

              {/* Outer Orbit Group (80s) */}
              <div className="absolute inset-0 animate-[spin_80s_linear_infinite]">
                {/* Cardiólogo (Top Left-ish) */}
                <OrbitItem angle={330} radius={290} label="Cardiólogo" duration="80s" />
                {/* Pediatra (Bottom Right) */}
                <OrbitItem angle={140} radius={290} label="Pediatra" duration="80s" />
                {/* Neurólogo (Bottom Left) */}
                <OrbitItem angle={220} radius={290} label="Neurólogo" duration="80s" />
              </div>

              {/* Inner Orbit Group (60s - faster/different) */}
              <div className="absolute inset-0 flex items-center justify-center animate-[spin_60s_linear_infinite_reverse]">
                {/* Container sized to inner ring for easier centering logic or just offset */}
                <div className="absolute w-[380px] h-[380px]">
                  {/* Psiquiatra (Top Right) */}
                  <OrbitItem angle={45} radius={190} label="Psiquiatra" duration="60s" reverse />
                  {/* Ginecóloga (Bottom Right) */}
                  <OrbitItem angle={135} radius={190} label="Ginecóloga" duration="60s" reverse />
                </div>
              </div>

            </div>
          </MotionReveal>

          {/* Right Column: Content */}
          <div className="flex flex-col justify-center">
            <MotionReveal durationMs={740} delayMs={200}>
              <h2 className="text-[clamp(32px,4vw,54px)] font-medium leading-[1.1] tracking-tight text-white">
                Más de 50 especialidades <span className="text-white/40">compatibles</span>
              </h2>
              <p className="mt-6 text-lg text-white/60 leading-relaxed">
                DeepClinic Copilot entiende el idioma de tu especialidad. Diseñado para médicos, psicólogos, dentistas, fisioterapeutas y enfermeros.
              </p>
            </MotionReveal>

            <div className="mt-12 grid sm:grid-cols-2 gap-6">
              <MotionReveal durationMs={740} delayMs={300} className="h-full">
                <div className="h-full rounded-2xl border border-white/10 bg-white/5 backdrop-blur-sm p-6 hover:bg-white/10 transition-colors">
                  <h3 className="text-sm font-semibold text-white mb-3">IA destilada por especialidad</h3>
                  <p className="text-sm text-white/50 leading-relaxed">
                    Modelos propios entrenados con datos clínicos reales para cada especialidad, desde Medicina Interna hasta Cirugía.
                  </p>
                </div>
              </MotionReveal>

              <MotionReveal durationMs={740} delayMs={400} className="h-full">
                <div className="h-full rounded-2xl border border-white/10 bg-white/5 backdrop-blur-sm p-6 hover:bg-white/10 transition-colors">
                  <h3 className="text-sm font-semibold text-white mb-3">Menos ruido, más precisión</h3>
                  <p className="text-sm text-white/50 leading-relaxed">
                    Cada modelo se ajusta al lenguaje clínico de su especialidad para reducir errores y alucinaciones.
                  </p>
                </div>
              </MotionReveal>
            </div>
          </div>

        </div>
      </div>
    </section>
  );
}

// Helper to position items on a circle and counter-rotate them
function OrbitItem({ angle, radius, label, duration, reverse = false }: { angle: number, radius: number, label: string, duration: string, reverse?: boolean }) {
  const placementStyle = {
    transform: `rotate(${angle}deg) translateY(-${radius}px)`,
  };

  // Construct the animation class dynamically based on duration and direction
  // If parent is Normal, Child must be Reverse. If parent is Reverse, Child must be Normal.
  const animationClass = reverse
    ? `animate-[spin_${duration}_linear_infinite]`
    : `animate-[spin_${duration}_linear_infinite_reverse]`;

  return (
    <div
      className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-0 h-0 flex items-center justify-center"
      style={placementStyle}
    >
      <div className={`flex items-center justify-center ${animationClass}`}>
        {/* Counter-rotate the initial placement angle to keep text upright starts */}
        <div style={{ transform: `rotate(${-angle}deg)` }}>
          <div className="px-5 py-2.5 rounded-full bg-white shadow-[0_0_20px_rgba(255,255,255,0.15)] text-black text-base font-semibold whitespace-nowrap">
            {label}
          </div>
        </div>
      </div>
    </div>
  );
}
